import React, { ReactNode } from "react"
import { useIntl } from "react-intl"
import { BriefcaseIcon } from "../../icons/MiscIcons"
import { aarhusTechImg } from "./educationImages"
import { urImg, broenImg, elgigantenImg } from "./WorkImages"

export interface Resume {
    company: string,
    title: string,
    logo: () => ReactNode,
    start: {
      label: string,
      dateTime?: number
    },
    end: {
      label: string,
      dateTime?: number
    }
  }
  
  export function Resume() {
    const intl = useIntl()
  
    let resume: Resume[] = [
      {
        company: 'Universal Robots A/S',
        title: intl.$t({id: 'software-developer'}),
        logo: urImg,
        start: { label: 'jan.' + ' 2021' },
        end: {
          label: intl.$t({id: 'present'}),
          dateTime: new Date().getFullYear(),
        },
      },
      {
        company: 'BROEN Valve Technologies',
        title: intl.$t({id: 'student-worker'}),
        logo: broenImg,
        start: { label: 'aug. 2019' },
        end: { label: 'jan. 2021' },
      },
      {
        company: 'Aarhus Tech',
        title: intl.$t({id: 'apprentice'}),
        logo: aarhusTechImg,
        start: { label: 'jan. 2017' },
        end: { label: 'aug. 2017' },
      },
      {
        company: 'Elgiganten A/S',
        title: 'Merchandiser',
        logo: elgigantenImg,
        start: { label: (intl.$t({id: 'october-abbreviation'}) + ' 2015') },
        end: { label: 'aug. 2016' },
      },
    ]
  
    return (
      <div className="rounded-2xl border border-zinc-100 p-6 dark:border-zinc-700/40">
        <h2 className="flex text-sm font-semibold text-zinc-900 dark:text-zinc-100">
          <BriefcaseIcon className="h-6 w-6 flex-none" />
          <span className="ml-3">{intl.$t({id: 'work'})}</span>
        </h2>
        <ol className="mt-6 space-y-4">
          {resume.map((role: Resume, roleIndex) => (
            <li key={roleIndex} className="flex gap-4">
              <div className="relative mt-1 flex h-11 w-11 flex-none items-center justify-center rounded-full shadow-md shadow-zinc-800/5 ring-1 ring-zinc-900/5 dark:border dark:border-zinc-700/50 dark:bg-zinc-800 dark:ring-0">
                {role.logo()}
              </div>
              <dl className="flex flex-auto flex-wrap gap-x-2">
                <dt className="sr-only">{intl.$t({id: 'sr-company'})}</dt>
                <dd className="w-full flex-none text-sm font-medium text-zinc-900 dark:text-zinc-100">
                  {role.company}
                </dd>
                <dt className="sr-only">{intl.$t({id: 'sr-role'})}</dt>
                <dd className="text-xs text-zinc-500 dark:text-zinc-400">
                  {role.title}
                </dd>
                <dt className="sr-only">{intl.$t({id: 'sr-date'})}</dt>
                <dd
                  className="ml-auto text-xs text-zinc-400 dark:text-zinc-500"
                  aria-label={`${role.start.label ?? role.start} until ${role.end.label ?? role.end
                    }`}
                >
                  <time dateTime={(role.start.dateTime ?? role.start.label).toString()}>
                    {role.start.label ?? role.start}
                  </time>{' '}
                  <span aria-hidden="true">—</span>{' '}
                  <time dateTime={(role.end.dateTime ?? role.end).toString()}>
                    {role.end.label ?? role.end}
                  </time>
                </dd>
              </dl>
            </li>
          ))}
        </ol>
        {/*
        <Button href="#" variant="secondary" className="group mt-6 w-full">
          Download CV
          <ArrowDownIcon className="h-4 w-4 stroke-zinc-400 transition group-active:stroke-zinc-600 dark:group-hover:stroke-zinc-50 dark:group-active:stroke-zinc-50" />
        </Button>
        */}
      </div>
    )
  }